        log("[VALIDATE] Checking Ch5 5.1.1 status.yaml...")

        status_path = PROJECT_ROOT / "results" / "ch5" / "5.1.1" / "status.yaml"
        result = check_file_exists(file_path=status_path, min_size_bytes=100)

